class Solution {
    public:
        bool isValidSudoku(vector<vector<int>>& board) {
            set<int> seen;
            for (int i = 0; i < 9; i++) {
                for (int j = 0; j < 9; j++) {
                    if (board[i][j] != 0) {
                        int num = board[i][j];
                        vector<int> row(9);
                        for (int k = 0; k < 9; k++) {
                            row[k] = board[i][k];
                        }
                        vector<int> col(9);
                        for (int k = 0; k < 9; k++) {
                            col[k] = board[k][j];
                        }
                        vector<int> box(9);
                        int boxIndex = (i / 3) * 3 + j / 3;
                        for (int k = 0; k < 9; k++) {
                            box[k] = board[(i / 3) * 3 + k / 3][(j / 3) * 3 + k % 3];
                        }
                        if (seen.find(num) != seen.end() || find(row.begin(), row.end(), num) != row.end() || find(col.begin(), col.end(), num) != col.end() || find(box.begin(), box.end(), num) != box.end()) {
                            return false;
                        }
                        seen.insert(num);
                    }
                }
            }
            return true;
        }
};
